package uuid;

import liquidjava.specification.ExternalRefinementsFor;
import liquidjava.specification.Refinement;
import liquidjava.specification.StateRefinement;
import liquidjava.specification.StateSet;
import java.util.UUID;

@ExternalRefinementsFor("java.util.UUID")
@StateSet({"nottimebased", "maybetimebased"})
public interface UUIDRefinements {

    @StateRefinement(to = "maybetimebased(this)")
    public void UUID(long mostSigBits, long leastSigBits);

    @StateRefinement(to = "nottimebased(_)")
    public UUID randomUUID();

    @StateRefinement(to = "nottimebased(_)")
    public UUID nameUUIDFromBytes(byte[] name);

    @StateRefinement(to = "maybetimebased(_)")
    public UUID fromString(String name);

    @StateRefinement(from = "maybetimebased(this)", to = "maybetimebased(this)")
    public long getLeastSignificantBits();

    @StateRefinement(from = "nottimebased(this)", to = "nottimebased(this)")
    public long getLeastSignificantBits(long mostSigBits);

    @StateRefinement(from = "maybetimebased(this)", to = "maybetimebased(this)")
    public long getMostSignificantBits();

    @StateRefinement(from = "nottimebased(this)", to = "nottimebased(this)")
    public long getMostSignificantBits(long leastSigBits);

    @StateRefinement(from = "maybetimebased(this) || nottimebased(this)")
    @Refinement("_ >= 1 && _ <= 4")
    public int version();

    @StateRefinement(from = "maybetimebased(this) || nottimebased(this)")
    @Refinement("_ >= 0")
    public int variant();

    @StateRefinement(from = "maybetimebased(this)")
    @Refinement("_ >= 0")
    public long timestamp();

    @StateRefinement(from = "maybetimebased(this)")
    @Refinement("_ >= 0 && _ <= 16383")
    public int clockSequence();

    @StateRefinement(from = "maybetimebased(this)")
    @Refinement("_ >= 0")
    public long node();

    @StateRefinement(from = "maybetimebased(this) || nottimebased(this)")
    public String toString();

    @StateRefinement(from = "maybetimebased(this) || nottimebased(this)")
    public int hashCode();

    @StateRefinement(from = "maybetimebased(this) || nottimebased(this)")
    public boolean equals(Object obj);

    @StateRefinement(from = "maybetimebased(this) || nottimebased(this)")
    @Refinement("_ >= -1 && _ <= 1")
    public int compareTo(UUID val);

}

